import 'package:flutter/material.dart';import '../../design_system/app_colors.dart';import '../../design_system/app_spacing.dart';import '../../design_system/app_typography.dart';import '../../design_system/ds_buttons.dart';import '../../design_system/ds_input_field.dart';import '../../models/category.dart';import '../../services/mock_data_service.dart';class CategorySelectorScreenResult {  final Category? category;  final bool createNew;  CategorySelectorScreenResult({this.category, this.createNew = false});}class CategorySelectorScreen extends StatefulWidget {  const CategorySelectorScreen({super.key});  @override  State<CategorySelectorScreen> createState() => _CategorySelectorScreenState();}@overrideclass _CategorySelectorScreenState extends State<CategorySelectorScreen> {  final TextEditingController _searchController = TextEditingController();  List<Category> _filteredCategories = [];  Category? _selectedCategory;  @override  void initState() {    super.initState();    _filteredCategories = MockDataService.categories;    _searchController.addListener(_filterCategories);  }  @override  void dispose() {    _searchController.removeListener(_filterCategories);    _searchController.dispose();    super.dispose();  }  void _filterCategories() {    final query = _searchController.text.toLowerCase();    setState(() {      _filteredCategories = MockDataService.categories          .where((cat) => cat.name.toLowerCase().contains(query))          .toList();    });  }  @override  Widget build(BuildContext context) {    return Scaffold(      backgroundColor: AppColors.background,      appBar: AppBar(        title: Text('Select Category', style: AppTypography.h2),        leading: DsIconButton(          icon: Icons.close,          onPressed: () => Navigator.of(context).pop(),          backgroundColor: Colors.transparent,          iconColor: AppColors.textPrimary,        ),      ),      body: Column(        children: [          Padding(            padding: const EdgeInsets.symmetric(horizontal: AppSpacing.paddingLarge),            child: DsInputField(              controller: _searchController,              hintText: 'Search or create category...',              suffixIcon: _searchController.text.isNotEmpty                  ? DsIconButton(                      icon: Icons.clear,                      onPressed: () {                        _searchController.clear();                        _filterCategories();                      },                      size: AppSpacing.iconSizeMedium,                      backgroundColor: Colors.transparent,                      iconColor: AppColors.textSecondary,                    )                  : null,            ),          ),          SizedBox(height: AppSpacing.paddingMedium),          Expanded(            child: ListView(              children: [                _buildSectionTitle('Recently Used'),                _buildCategoryGrid(MockDataService.categories.take(4).toList()), // Mock recently used                _buildSectionTitle('All Categories'),                _buildCategoryGrid(_filteredCategories),                Padding(                  padding: AppSpacing.screenPadding,                  child: DsSecondaryButton(                    text: 'Create New Category',                    onPressed: () {                      // TODO: Implement Create New Category flow                      ScaffoldMessenger.of(context).showSnackBar(                        const SnackBar(content: Text('Create New Category coming soon!')),                      );                    },                  ),                ),              ],            ),          ),          _buildConfirmationButton(context),        ],      ),    );  }  Widget _buildSectionTitle(String title) {    return Padding(      padding: const EdgeInsets.symmetric(        horizontal: AppSpacing.paddingLarge,        vertical: AppSpacing.paddingSmall,      ),      child: Text(        title,        style: AppTypography.body.copyWith(color: AppColors.textSecondary),      ),    );  }  Widget _buildCategoryGrid(List<Category> categories) {    return Padding(      padding: const EdgeInsets.symmetric(horizontal: AppSpacing.paddingLarge),      child: GridView.builder(        shrinkWrap: true,        physics: const NeverScrollableScrollPhysics(),        gridDelegate: const SliverGridDelegateWithFixedCrossAxisCount(          crossAxisCount: 3,          crossAxisSpacing: AppSpacing.paddingMedium,          mainAxisSpacing: AppSpacing.paddingMedium,          childAspectRatio: 1.0,        ),        itemCount: categories.length,        itemBuilder: (context, index) {          final category = categories[index];          final isSelected = _selectedCategory == category;          return GestureDetector(            onTap: () {              setState(() {                _selectedCategory = category;              });            },            child: AnimatedContainer(              duration: const Duration(milliseconds: 150),              curve: Curves.easeOut,              decoration: BoxDecoration(                color: AppColors.surface,                borderRadius: BorderRadius.circular(AppSpacing.borderRadiusMedium),                border: isSelected                    ? Border.all(color: AppColors.primary, width: 2)                    : Border.all(color: Colors.transparent, width: 2),                boxShadow: isSelected                    ? [                        BoxShadow(                          color: AppColors.primary.withOpacity(0.3),                          blurRadius: 8,                          spreadRadius: 1,                        ),                      ]                    : [],              ),              child: Column(                mainAxisAlignment: MainAxisAlignment.center,                children: [                  Icon(                    category.icon,                    color: isSelected ? AppColors.primary : AppColors.textSecondary,                    size: AppSpacing.iconSizeMedium * 1.5,                  ),                  SizedBox(height: AppSpacing.paddingSmall / 2),                  Text(                    category.name,                    style: AppTypography.caption.copyWith(                      color: isSelected ? AppColors.primary : AppColors.textSecondary,                    ),                    textAlign: TextAlign.center,                    maxLines: 1,                    overflow: TextOverflow.ellipsis,                  ),                ],              ),            ),          );        },      ),    );  }  Widget _buildConfirmationButton(BuildContext context) {    return Container(      padding: AppSpacing.screenPadding.copyWith(top: AppSpacing.paddingMedium),      decoration: BoxDecoration(        color: AppColors.surface,        boxShadow: [          BoxShadow(            color: Colors.black.withOpacity(0.2),            offset: const Offset(0, -2),            blurRadius: 8,          ),        ],      ),      child: DsPrimaryButton(        text: 'Confirm',        onPressed: _selectedCategory == null            ? null            : () {                Navigator.of(context).pop(                  CategorySelectorScreenResult(category: _selectedCategory),                );              },      ),    );  }}